import { GoogleGenAI, Type, FunctionDeclaration } from "@google/genai";
import { CarState } from "../types";

const controlCarFeatureDeclaration: FunctionDeclaration = {
  name: 'controlCarFeature',
  parameters: {
    type: Type.OBJECT,
    description: 'Controla funcionalidades específicas do Peugeot e-2008, como luzes, trancagem, ar condicionado ou modo de condução.',
    properties: {
      feature: {
        type: Type.STRING,
        description: 'A funcionalidade a controlar.',
        enum: ['lightsOn', 'locked', 'climateOn', 'drivingMode'],
      },
      value: {
        type: Type.STRING,
        description: 'O valor para a funcionalidade. Para luzes, lock e climate use "true" ou "false". Para drivingMode use "Eco", "Comfort" ou "Sport".',
      }
    },
    required: ['feature', 'value'],
  },
};

export const getSmartInsights = async (state: CarState): Promise<string[]> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const prompt = `Como assistente inteligente Peugeot e-GT, analisa: Bateria ${state.batteryLevel}%, Autonomia ${state.rangeKm}km, Modo ${state.drivingMode}. O condutor chama-se Leonardo. Dá 2 conselhos ultra-curtos e premium.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    const text = response.text || "";
    return text.split('\n').filter(t => t.trim().length > 0).slice(0, 2);
  } catch (error) {
    return ["Sistemas Peugeot optimizados.", "Bateria em condições ideais."];
  }
};

export const processUserCommand = async (command: string, currentState: CarState) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `O utilizador Leonardo disse: "${command}". O estado atual é: ${JSON.stringify(currentState)}. Use as ferramentas para ajudar o utilizador ou responda educadamente.`,
      config: {
        tools: [{ functionDeclarations: [controlCarFeatureDeclaration] }],
      },
    });

    return {
      text: response.text,
      functionCalls: response.functionCalls
    };
  } catch (error) {
    console.error("AI Command Error:", error);
    return { text: "Desculpe Leonardo, houve um erro na conexão com o sistema central.", functionCalls: [] };
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import Dashboard from './components/Dashboard';
import HistoryCharts from './components/HistoryCharts';
import { CarState, TelemetryPoint } from './types';
import { fetchCarData, fetchHistoryData, updateCarCommand, exchangeCodeForToken } from './services/apiService';
import { getSmartInsights, processUserCommand } from './services/geminiService';

const App: React.FC = () => {
  const [carState, setCarState] = useState<CarState | null>(null);
  const [history, setHistory] = useState<TelemetryPoint[]>([]);
  const [insights, setInsights] = useState<string[]>([]);
  const [loading, setLoading] = useState(true);
  const [showWelcome, setShowWelcome] = useState(false);
  const [command, setCommand] = useState("");
  const [isProcessingAI, setIsProcessingAI] = useState(false);
  const [aiResponse, setAiResponse] = useState<string | null>(null);

  const initRef = useRef(false);

  useEffect(() => {
    if (initRef.current) return;
    initRef.current = true;

    const init = async () => {
      try {
        setLoading(true);
        const urlParams = new URLSearchParams(window.location.search);
        const code = urlParams.get('code');

        if (code) {
          await exchangeCodeForToken(code);
          window.history.replaceState({}, document.title, window.location.pathname);
        }

        const [data, historyData] = await Promise.all([
          fetchCarData(),
          fetchHistoryData()
        ]);

        setCarState(data);
        setHistory(historyData);

        const aiTips = await getSmartInsights(data);
        setInsights(aiTips);

        setLoading(false);
        setShowWelcome(true);
        setTimeout(() => setShowWelcome(false), 3500);
      } catch (e) {
        console.error("Erro na inicialização:", e);
        setLoading(false);
      }
    };

    init();

    const interval = setInterval(async () => {
      const data = await fetchCarData();
      setCarState(prev => {
        if (JSON.stringify(prev) === JSON.stringify(data)) return prev;
        return data;
      });
    }, 10000);

    return () => clearInterval(interval);
  }, []);

  const handleAction = async (key: keyof CarState, val: any) => {
    if (!carState) return;
    const newState = { ...carState, [key]: val };
    setCarState(newState);
    await updateCarCommand(key, val);
  };

  const handleAICommand = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!command.trim() || !carState || isProcessingAI) return;

    setIsProcessingAI(true);
    setAiResponse(null);

    const result = await processUserCommand(command, carState);

    if (result.functionCalls && result.functionCalls.length > 0) {
      for (const fc of result.functionCalls) {
        if (fc.name === 'controlCarFeature') {
          const { feature, value } = fc.args as any;
          let typedValue: any = value;
          if (value === 'true') typedValue = true;
          if (value === 'false') typedValue = false;

          await handleAction(feature as keyof CarState, typedValue);
        }
      }
    }

    if (result.text) {
      setAiResponse(result.text);
      setTimeout(() => setAiResponse(null), 5000);
    }

    setCommand("");
    setIsProcessingAI(false);
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-black">
        <div className="text-center space-y-6">
          <div className="w-16 h-16 border-4 border-cyan-400 border-t-transparent rounded-full animate-spin mx-auto shadow-[0_0_20px_#22d3ee]"></div>
          <h2 className="text-cyan-400 font-black uppercase tracking-[0.5em] text-xs">Sincronizando Sistemas Peugeot...</h2>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#050507] text-white selection:bg-cyan-400 selection:text-black pb-32">
      <AnimatePresence mode="wait">
        {showWelcome && (
          <motion.div 
            key="welcome-screen"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0, scale: 1.1, filter: "blur(20px)" }}
            transition={{ duration: 0.8 }}
            className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center overflow-hidden"
          >
            <div className="absolute inset-0 overflow-hidden pointer-events-none">
              <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full h-full bg-cyan-500/10 blur-[180px] rounded-full animate-pulse"></div>
            </div>

            <motion.div 
              initial={{ y: 20, opacity: 0 }}
              animate={{ y: 0, opacity: 1 }}
              transition={{ delay: 0.3, duration: 0.8, ease: "easeOut" }}
              className="relative text-center space-y-4"
            >
              <motion.div 
                initial={{ width: 0 }}
                animate={{ width: "100%" }}
                transition={{ delay: 0.5, duration: 1 }}
                className="h-[2px] bg-cyan-400 mx-auto shadow-[0_0_15px_#22d3ee]"
              />
              <h2 className="text-zinc-500 text-[10px] font-black uppercase tracking-[1em] mb-4">Sistemas Ativos</h2>
              <h1 className="text-7xl font-black italic tracking-tighter text-white">
                Peugeot <span className="text-cyan-400 not-italic">Leonardo</span>
              </h1>
              <motion.p 
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: 1.5 }}
                className="text-zinc-600 font-bold uppercase tracking-[0.4em] text-[10px]"
              >
                Intelligent Electric Experience
              </motion.p>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      <div className="fixed top-0 left-0 w-full h-full pointer-events-none overflow-hidden z-0">
        <div className="absolute top-[-20%] left-[-10%] w-[60%] h-[60%] bg-cyan-500/5 blur-[150px] rounded-full"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-blue-500/5 blur-[150px] rounded-full"></div>
      </div>

      <motion.main 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ duration: 1, delay: showWelcome ? 3.5 : 0 }}
        className="relative z-10 space-y-20"
      >
        <Dashboard 
          state={carState!} 
          onAction={handleAction} 
          insights={insights}
        />

        <section className="max-w-6xl mx-auto px-6">
          <div className="flex items-center space-x-4 mb-10">
            <h2 className="text-3xl font-black italic tracking-tighter">Fluxo de <span className="text-cyan-400">Energia</span></h2>
            <div className="h-px flex-grow bg-white/5"></div>
          </div>
          <HistoryCharts data={history} />
        </section>
      </motion.main>

      {/* Floating Command Center */}
      <div className="fixed bottom-8 left-1/2 -translate-x-1/2 w-full max-w-xl px-4 z-[60]">
        <AnimatePresence>
          {aiResponse && (
            <motion.div 
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.9 }}
              className="mb-4 p-4 glass-card rounded-2xl border-cyan-400/30 text-center"
            >
              <p className="text-cyan-400 text-sm font-medium italic">"{aiResponse}"</p>
            </motion.div>
          )}
        </AnimatePresence>

        <form 
          onSubmit={handleAICommand}
          className="relative group"
        >
          <div className="absolute -inset-1 bg-gradient-to-r from-cyan-400 to-blue-600 rounded-full blur opacity-25 group-hover:opacity-50 transition duration-1000 group-focus-within:opacity-100"></div>
          <div className="relative flex items-center bg-black/80 backdrop-blur-3xl rounded-full border border-white/10 p-2 pl-6">
            <input 
              type="text" 
              value={command}
              onChange={(e) => setCommand(e.target.value)}
              placeholder="Comando de voz: 'Liga o ar condicionado'..."
              className="bg-transparent border-none focus:ring-0 flex-grow text-sm font-medium text-white placeholder-zinc-600"
              disabled={isProcessingAI}
            />
            <button 
              type="submit"
              disabled={isProcessingAI || !command.trim()}
              className={`w-10 h-10 rounded-full flex items-center justify-center transition-all ${
                isProcessingAI ? 'bg-zinc-800' : 'bg-cyan-400 text-black hover:scale-110 active:scale-95'
              }`}
            >
              {isProcessingAI ? (
                <div className="w-4 h-4 border-2 border-white/20 border-t-white rounded-full animate-spin"></div>
              ) : (
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13 5l7 7-7 7M5 5l7 7-7 7" /></svg>
              )}
            </button>
          </div>
        </form>
      </div>

      <footer className="relative z-10 py-12 text-center pb-32">
        <p className="text-zinc-700 text-[10px] font-black uppercase tracking-[1em]">Peugeot Pure Electric Technology</p>
      </footer>
    </div>
  );
};

export default App;

import { CarState, TelemetryPoint, DrivingMode } from "../types";

const SMARTCAR_CONFIG = {
  clientId: 'bbcfa8a5-2903-4a1c-bfb5-64559400bfa0',
  clientSecret: 'bbcfa8a5-2903-4a1c-bfb5-64559400bfa0',
  redirectUri: 'https://aistudio.google.com',
  scope: 'read_vehicle_info read_battery',
};

let mockState: CarState = {
  batteryLevel: 74,
  isCharging: false,
  rangeKm: 222,
  odometer: 12450,
  lightsOn: false,
  locked: true,
  climateOn: false,
  insideTemp: 21,
  outsideTemp: 18,
  health: 98.4,
  lastUpdate: new Date().toISOString(),
  drivingMode: 'Comfort',
  isConnected: false
};

const getModeFactor = (mode: DrivingMode): number => {
  switch (mode) {
    case 'Eco': return 1.15;
    case 'Sport': return 0.85;
    default: return 1.0;
  }
};

export const getSmartcarAuthUrl = () => {
  const url = new URL('https://connect.smartcar.com/oauth/authorize');
  url.searchParams.set('response_type', 'code');
  url.searchParams.set('client_id', SMARTCAR_CONFIG.clientId);
  url.searchParams.set('redirect_uri', SMARTCAR_CONFIG.redirectUri);
  url.searchParams.set('scope', SMARTCAR_CONFIG.scope);
  url.searchParams.set('mode', 'test');
  return url.toString();
};

export const exchangeCodeForToken = async (code: string) => {
  try {
    const response = await fetch('https://auth.smartcar.com/oauth/token', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Authorization': 'Basic ' + btoa(`${SMARTCAR_CONFIG.clientId}:${SMARTCAR_CONFIG.clientSecret}`)
      },
      body: new URLSearchParams({
        grant_type: 'authorization_code',
        code: code,
        redirect_uri: SMARTCAR_CONFIG.redirectUri,
      })
    });

    const data = await response.json();
    if (data.access_token) {
      localStorage.setItem('smartcar_token', data.access_token);
      return data.access_token;
    }
  } catch (error) {
    console.error("Smartcar Auth Error:", error);
  }
  return null;
};

export const fetchCarData = async (): Promise<CarState> => {
  const token = localStorage.getItem('smartcar_token');

  if (token) {
    try {
      const vResponse = await fetch('https://api.smartcar.com/v2.0/vehicles', {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      const vData = await vResponse.json();

      if (vData.vehicles && vData.vehicles.length > 0) {
        const vehicleId = vData.vehicles[0];
        const bResponse = await fetch(`https://api.smartcar.com/v2.0/vehicles/${vehicleId}/battery`, {
          headers: { 'Authorization': `Bearer ${token}` }
        });
        const bData = await bResponse.json();

        mockState.batteryLevel = Math.round((bData.percentRemaining || 0.74) * 100);
        mockState.rangeKm = Math.round(bData.range || 222); 
        mockState.isConnected = true;
        mockState.lastUpdate = new Date().toISOString();
      }
    } catch (error) {
      console.warn("Smartcar Sync Error, using fallback.");
      mockState.isConnected = false;
    }
  }

  // Simular pequeno dreno ou carga se estiver ligado
  if (mockState.isCharging) {
    mockState.batteryLevel = Math.min(100, mockState.batteryLevel + 0.1);
  } else if (mockState.climateOn) {
    mockState.batteryLevel = Math.max(0, mockState.batteryLevel - 0.01);
  }

  const factor = getModeFactor(mockState.drivingMode);
  mockState.rangeKm = Math.round((mockState.batteryLevel / 100) * 310 * factor);

  return { ...mockState };
};

export const fetchHistoryData = async (): Promise<TelemetryPoint[]> => {
  const history: TelemetryPoint[] = [];
  const now = new Date();

  for (let i = 12; i >= 0; i--) {
    const time = new Date(now.getTime() - i * 3600000);
    const baseBattery = 85 - (12 - i) * 2;
    history.push({
      time: time.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      battery: Math.max(0, baseBattery + Math.random() * 3),
      range: Math.max(0, (baseBattery * 3.0) + Math.random() * 5),
      consumption: 14 + Math.random() * 4
    });
  }
  return history;
};

export const updateCarCommand = async (command: keyof CarState, value: any): Promise<void> => {
  // @ts-ignore
  mockState[command] = value;

  // Atualização imediata de lógica derivada
  if (command === 'batteryLevel' || command === 'drivingMode') {
     const factor = getModeFactor(mockState.drivingMode);
     mockState.rangeKm = Math.round((mockState.batteryLevel / 100) * 310 * factor);
  }
};
